-- 9 Craft Kitchen and Bar (46 dishes)
DELETE FROM dishes WHERE restaurant_id = (SELECT id FROM restaurants WHERE name = '9 Craft Kitchen and Bar');
UPDATE restaurants SET menu_section_order = ARRAY['SALADS & SOUPS', 'SMALLER & SHAREABLE', 'PASTAS & RISOTTO', 'ENTREES', 'SIDES'] WHERE name = '9 Craft Kitchen and Bar';

