SELECT r.name, COUNT(d.id) as dishes FROM restaurants r JOIN dishes d ON d.restaurant_id = r.id WHERE r.name IN (
  '9 Craft Kitchen and Bar', 'ArtCliff Diner', 'Back Door Donuts', 'Bangkok Cuisine', 'Beach Road', 'Bettini Restaurant', 'Black Dog', 'Catboat', 'Coop de Ville', 'Cozy Corner', 'Dock Street', 'Edgartown Pizza', 'Espresso Love', 'Indigo', 'Lookout Tavern', 'MV Salads', 'Mo''s Lunch', 'Nat''s Nook', 'Ocean Club', 'Offshore Ale Company', 'Porto Pizza', 'Rockfish', 'Sharky''s Cantina', 'Square Rigger', 'The Attic', 'The Barn Bowl & Bistro', 'Town Bar', 'Waterside Market', 'Wolf''s Den Pizzeria'
) GROUP BY r.name ORDER BY dishes DESC;